def cycle(cycle_pid) do
  Agent.get_and_update(cycle_pid, fn
    {[], items} ->
      [h | t] = Enum.shuffle(items)
      {h, {t, items}}

    {[h | t], items} ->
      {h, {t, items}}
  end)
end
